class Solution:
    def nextGreaterElement(self, n):
        from itertools import permutations
        digits = str(n)
        seen = set()
        for p in permutations(digits):
            if p[0] == '0':
                continue
            v = int(''.join(p))
            if v > n and v <= 2147483647:
                seen.add(v)
        return min(seen) if seen else -1

