class Solution:
    def nextGreaterElement(self, n):
        d = list(str(n))
        i = len(d) - 2
        while i >= 0 and d[i] >= d[i + 1]:
            i -= 1
        if i < 0:
            return -1
        j = len(d) - 1
        while d[j] <= d[i]:
            j -= 1
        d[i], d[j] = d[j], d[i]
        d[i + 1:] = reversed(d[i + 1:])
        v = int(''.join(d))
        return v if v <= 2147483647 else -1

