var nextGreaterElement = function(n) {
    const d = String(n).split('');
    let i = d.length - 2;
    while (i >= 0 && d[i] >= d[i + 1]) i--;
    if (i < 0) return -1;
    let j = d.length - 1;
    while (d[j] <= d[i]) j--;
    [d[i], d[j]] = [d[j], d[i]];
    let lo = i + 1, hi = d.length - 1;
    while (lo < hi) { [d[lo], d[hi]] = [d[hi], d[lo]]; lo++; hi--; }
    const v = Number(d.join(''));
    return v <= 2147483647 ? v : -1;
};
